 53	        rule and_expr() -> Result<Expr, ParseError>
 54	            = l:unary_expr() rest:(_ "and" _ r:unary_expr() { r })* {
 55	                rest.into_iter().fold(l, |acc, r| Ok(Expr::And(Box::new(acc?), Box::new(r?))))
 56	            }
